mapper.delete:
		DELETE FROM xxl_job_logglue
		WHERE id NOT in(
			SELECT id FROM(
                select * from (
                    SELECT row_number() over(ORDER BY update_time desc) r,id FROM xxl_job_logglue
                    WHERE job_id = #{jobId}
                    )
                    where r between 0 and #{limit}
                ) t1
		) AND job_id = #{jobId}
